def A086810row(n: int) -> list[int]:
    if n == 0: return [1]
    row = [0] * (n + 1); row[1] = 1
    for k in range(1, n):
        num = (n - k) * (n + k + 1)
        den = k * (k + 1)
        row[k + 1] = (row[k] * num) // den
    return row
